# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka import KafkaAdminClient
from kafka.admin import NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import TopicAlreadyExistsError, UnknownTopicOrPartitionError
import sys

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config):
    try:
        topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=config
        )
        admin_client.create_topics([topic], validate_only=False)
        print(f"Topic '{topic_name}' created successfully")
    except TopicAlreadyExistsError:
        print(f"Topic '{topic_name}' already exists")
    except Exception as e:
        print(f"Error creating topic '{topic_name}': {e}")

def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Topics:")
        for topic in topics:
            print(f"  {topic}")
    except Exception as e:
        print(f"Error listing topics: {e}")

def describe_topic(admin_client, topic_name):
    try:
        topic_configs = admin_client.describe_configs([
            ConfigResource(ConfigResourceType.TOPIC, topic_name)
        ])
        print(f"Configurations for topic '{topic_name}':")
        for resource, config in topic_configs.items():
            for key, value in config.resources[0].configs.items():
                print(f"  {key}: {value}")
    except UnknownTopicOrPartitionError:
        print(f"Topic '{topic_name}' not found")
    except Exception as e:
        print(f"Error describing topic '{topic_name}': {e}")

def delete_topic(admin_client, topic_name):
    try:
        admin_client.delete_topics([topic_name])
        print(f"Topic '{topic_name}' deleted successfully")
    except UnknownTopicOrPartitionError:
        print(f"Topic '{topic_name}' not found")
    except Exception as e:
        print(f"Error deleting topic '{topic_name}': {e}")

def main():
    parser = argparse.ArgumentParser(description="Kafka Cluster Administration Tool")
    parser.add_argument("--bootstrap-servers", default="localhost:9092", help="Bootstrap servers")
    parser.add_argument("--action", choices=["create", "list", "describe", "delete"], required=True, help="Action to perform")
    parser.add_argument("--topic", help="Topic name")
    parser.add_argument("--partitions", type=int, help="Number of partitions")
    parser.add_argument("--replication-factor", type=int, default=1, help="Replication factor")
    parser.add_argument("--config", nargs="*", help="Topic configuration as key=value pairs")
    
    args = parser.parse_args()
    
    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_servers)
    
    config_dict = {}
    if args.config:
        for item in args.config:
            key, value = item.split("=")
            config_dict[key] = value
    
    if args.action == "create":
        if not args.topic or not args.partitions:
            print("Topic name and number of partitions are required for create action")
            sys.exit(1)
        create_topic(admin_client, args.topic, args.partitions, args.replication_factor, config_dict)
    
    elif args.action == "list":
        list_topics(admin_client)
    
    elif args.action == "describe":
        if not args.topic:
            print("Topic name is required for describe action")
            sys.exit(1)
        describe_topic(admin_client, args.topic)
    
    elif args.action == "delete":
        if not args.topic:
            print("Topic name is required for delete action")
            sys.exit(1)
        delete_topic(admin_client, args.topic)

if __name__ == "__main__":
    main()